(function($) {
'use strict';
const VH360Events = {
init: function() {
this.bindEvents();
},
bindEvents: function() {
$('.vh360-event-filter').on('click', this.handleFilterClick);
$('#vh360-event-category').on('change', this.handleCategoryChange);
let searchTimeout;
$('#vh360-event-search').on('input', function() {
clearTimeout(searchTimeout);
searchTimeout = setTimeout(function() {
VH360Events.handleSearch();
}, 500);
});
$(document).on('click', '.vh360-events-pagination a', this.handlePaginationClick);
},
handleFilterClick: function(e) {
e.preventDefault();
const $btn = $(this);
const filter = $btn.data('filter');
$('.vh360-event-filter').removeClass('active');
$btn.addClass('active');
VH360Events.loadEvents(filter, 1);
},
handleCategoryChange: function() {
const filter = $('.vh360-event-filter.active').data('filter');
VH360Events.loadEvents(filter, 1);
},
handleSearch: function() {
const filter = $('.vh360-event-filter.active').data('filter');
VH360Events.loadEvents(filter, 1);
},
handlePaginationClick: function(e) {
e.preventDefault();
const $link = $(this);
const page = $link.text();
const filter = $('.vh360-event-filter.active').data('filter');
$('html, body').animate({
scrollTop: $('#vh360-events-list-container').offset().top - 100
}, 300);
VH360Events.loadEvents(filter, parseInt(page));
},
loadEvents: function(filter, page) {
const $container = $('#vh360-events-list-container');
const search = $('#vh360-event-search').val();
const category = $('#vh360-event-category').val();
$container.html('<div class="vh360-events-loading"><div class="vh360-spinner"></div></div>');
$.ajax({
url: vh360Events.ajaxUrl,
type: 'POST',
data: {
action: 'vh360_load_events',
nonce: vh360Events.nonce,
filter: filter || 'upcoming',
page: page || 1,
search: search,
category: category
},
success: function(response) {
if (response.success) {
$container.html(response.data.html);
if (response.data.pagination) {
VH360Events.updatePagination(response.data.pagination);
}
} else {
$container.html('<div class="vh360-events-error">' + response.data.message + '</div>');
}
},
error: function() {
$container.html('<div class="vh360-events-error">' + vh360Events.i18n.error + '</div>');
}
});
},
updatePagination: function(pagination) {
}
};
const VH360EventRSVP = {
init: function() {
this.bindEvents();
},
bindEvents: function() {
$('.vh360-event-rsvp-btn').on('click', this.handleRsvp);
},
handleRsvp: function(e) {
e.preventDefault();
const $btn = $(this);
const eventId = $btn.data('event-id');
if ($btn.prop('disabled')) {
return;
}
$btn.prop('disabled', true);
$.ajax({
url: vh360Events.ajaxUrl,
type: 'POST',
data: {
action: 'vh360_event_rsvp',
nonce: vh360Events.nonce,
event_id: eventId
},
success: function(response) {
if (response.success) {
const isRsvpd = response.data.is_rsvpd;
const count = response.data.count;
if (isRsvpd) {
$btn.addClass('vh360-event-rsvpd');
$btn.find('.vh360-rsvp-text').text(vh360Events.i18n.rsvpd || 'RSVP\'d');
$btn.find('svg').html('<path d="M22 11.08V12a10 10 0 1 1-5.93-9.14"></path><polyline points="22 4 12 14.01 9 11.01"></polyline>');
} else {
$btn.removeClass('vh360-event-rsvpd');
$btn.find('.vh360-rsvp-text').text(vh360Events.i18n.rsvp || 'RSVP');
$btn.find('svg').html('<path d="M16 21v-2a4 4 0 0 0-4-4H5a4 4 0 0 0-4 4v2"></path><circle cx="8.5" cy="7" r="4"></circle><line x1="20" y1="8" x2="20" y2="14"></line><line x1="23" y1="11" x2="17" y2="11"></line>');
}
$btn.find('.vh360-rsvp-count').text('(' + count + ')');
VH360EventRSVP.showNotice('success', response.data.message);
} else {
VH360EventRSVP.showNotice('error', response.data.message);
}
},
error: function() {
VH360EventRSVP.showNotice('error', vh360Events.i18n.error);
},
complete: function() {
$btn.prop('disabled', false);
}
});
},
showNotice: function(type, message) {
const $notice = $('<div class="vh360-event-notice vh360-event-notice-' + type + '">' + message + '</div>');
$('body').append($notice);
setTimeout(function() {
$notice.addClass('vh360-event-notice-show');
}, 10);
setTimeout(function() {
$notice.removeClass('vh360-event-notice-show');
setTimeout(function() {
$notice.remove();
}, 300);
}, 3000);
}
};
const VH360EventImageLightbox = {
trigger: null,
init: function() {
this.bindEvents();
},
bindEvents: function() {
var self = this;
$(document).on('click', '.vh360-event-featured-image-trigger, .vh360-event-image-lightbox-trigger', function() {
self.trigger = this;
self.open($(this).data('full-image'), $(this).data('image-alt'));
});
$(document).on('click', '.vh360-event-image-lightbox-close, .vh360-event-image-lightbox-backdrop', function() {
self.close();
});
$(document).on('keydown', function(event) {
if (event.key === 'Escape' && $('.vh360-event-image-lightbox').hasClass('is-open')) {
self.close();
}
});
},
ensureMarkup: function() {
if ($('.vh360-event-image-lightbox').length) {
return;
}
var imagePreviewLabel = (
typeof vh360Events !== 'undefined' &&
vh360Events.i18n &&
vh360Events.i18n.imagePreview
) ? vh360Events.i18n.imagePreview : 'Event image preview';
var closeImageLabel = (
typeof vh360Events !== 'undefined' &&
vh360Events.i18n &&
vh360Events.i18n.closeImage
) ? vh360Events.i18n.closeImage : 'Close image preview';
$('body').append(
'<div class="vh360-event-image-lightbox" role="dialog" aria-modal="true" aria-label="' + imagePreviewLabel + '">' +
'<div class="vh360-event-image-lightbox-backdrop"></div>' +
'<div class="vh360-event-image-lightbox-content">' +
'<button type="button" class="vh360-event-image-lightbox-close" aria-label="' + closeImageLabel + '">&times;</button>' +
'<img src="" alt="">' +
'</div>' +
'</div>'
);
},
open: function(imageUrl, imageAlt) {
if (!imageUrl) {
return;
}
this.ensureMarkup();
var $lightbox = $('.vh360-event-image-lightbox');
var $image    = $lightbox.find('img');
$image.attr('src', imageUrl);
$image.attr('alt', imageAlt || '');
$('body').addClass('vh360-event-lightbox-open');
$lightbox.addClass('is-open');
$lightbox.find('.vh360-event-image-lightbox-close').trigger('focus');
},
close: function() {
var $lightbox = $('.vh360-event-image-lightbox');
$lightbox.removeClass('is-open');
$('body').removeClass('vh360-event-lightbox-open');
$lightbox.find('img').attr('src', '').attr('alt', '');
if (this.trigger) {
$(this.trigger).trigger('focus');
this.trigger = null;
}
}
};
$(document).ready(function() {
if (typeof vh360Events !== 'undefined') {
VH360Events.init();
VH360EventRSVP.init();
}
VH360EventImageLightbox.init();
});
})(jQuery);
